features.snippet:
interface tf #(
  parameter NK = 1
) (
  input int status_regs [NK]
);

bit [NK-1:0] ftmp, stmp;
foreach (status_regs [index]) begin
  stmp[index] = fs(status_regs[index]);
  ftmp[index] = ff(status_regs[index]);
end

always_comb begin int code;
  if (done === 1'b1) begin
    bit [NK-1:0] ftmp, stmp;
  end
end
